package com.school.sis.grade.entity;
import com.school.sis.common.audit.AuditableEntity; import com.school.sis.setup.entity.*; import jakarta.persistence.*; import java.math.BigDecimal; import java.util.*;
@Entity @Table(name="grading_templates") public class GradingTemplate extends AuditableEntity {
 @Id private UUID id; @Column(name="template_code",nullable=false,unique=true) private String templateCode; @Column(name="template_name",nullable=false) private String templateName; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="program_id") private Program program; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="course_id") private Course course; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="scale_id") private GradingScale scale; @Column(nullable=false) private int version=1; @Column(name="midterm_weight",nullable=false) private BigDecimal midtermWeight; @Column(name="final_weight",nullable=false) private BigDecimal finalWeight; @Enumerated(EnumType.STRING) @Column(nullable=false) private ActiveStatus status=ActiveStatus.ACTIVE; @OneToMany(mappedBy="template",cascade=CascadeType.ALL,orphanRemoval=true) private List<GradingTemplateCategory> categories=new ArrayList<>();
 @PrePersist void pre(){if(id==null)id=UUID.randomUUID();} public UUID getId(){return id;} public String getTemplateCode(){return templateCode;} public void setTemplateCode(String v){templateCode=v;} public String getTemplateName(){return templateName;} public void setTemplateName(String v){templateName=v;} public Program getProgram(){return program;} public void setProgram(Program v){program=v;} public Course getCourse(){return course;} public void setCourse(Course v){course=v;} public GradingScale getScale(){return scale;} public void setScale(GradingScale v){scale=v;} public int getVersion(){return version;} public void setVersion(int v){version=v;} public BigDecimal getMidtermWeight(){return midtermWeight;} public void setMidtermWeight(BigDecimal v){midtermWeight=v;} public BigDecimal getFinalWeight(){return finalWeight;} public void setFinalWeight(BigDecimal v){finalWeight=v;} public ActiveStatus getStatus(){return status;} public void setStatus(ActiveStatus v){status=v;} public List<GradingTemplateCategory> getCategories(){return categories;} public void setCategories(List<GradingTemplateCategory> v){categories.clear();if(v!=null)v.forEach(this::addCategory);} public void addCategory(GradingTemplateCategory c){c.setTemplate(this);categories.add(c);}
}
